#define IN_RANGE(x, min, max) ((x) >= (min) && (x) <= (max))
#define MIN(a, b)             ((a) <= (b) ? (a) : (b))

__kernel void dynproc_kernel(
    int iteration,
    __global int* gpuWall,
    __global int* gpuSrc,
    __global int* gpuDst,
    int cols,
    int rows,
    int startStep,
    int borderCols,
    int halo,
    __local int* prev,
    __local int* curr,
    __global int* outputBuffer)
{
    int bx = get_group_id(0);
    int tx = get_local_id(0);
    int blockSize = (int)get_local_size(0);

    int baseBlockCols = blockSize - borderCols * 2;
    int maxGroups = cols / baseBlockCols + ((cols % baseBlockCols) == 0 ? 0 : 1);
    if (bx >= maxGroups) {
        return;
    }

    int smallBlockCols = blockSize - iteration * halo * 2;
    int blkX = smallBlockCols * bx - borderCols;
    int blkXmax = blkX + blockSize - 1;
    int xidx = blkX + tx;

    int validXmin = (0 > blkX) ? -blkX : 0;
    int validXmax = (cols - 1 < blkXmax) ? blockSize - 1 - (blkXmax - cols + 1) : blockSize - 1;

    int W = tx - 1;
    int E = tx + 1;

    W = (validXmin > W) ? validXmin : W;
    E = (validXmax < E) ? validXmax : E;

    int isValid = IN_RANGE(tx, validXmin, validXmax);

    if (IN_RANGE(xidx, 0, cols - 1)) {
        prev[tx] = gpuSrc[xidx];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    int computed = 0;
    for (int i = 0; i < iteration; i++) {
        computed = 0;

        if (IN_RANGE(tx, i + 1, blockSize - i - 2) && isValid) {
            computed = 1;
            int left = prev[W];
            int up = prev[tx];
            int right = prev[E];
            int shortest = MIN(left, up);
            shortest = MIN(shortest, right);
            int index = cols * (startStep + i) + xidx;
            curr[tx] = shortest + gpuWall[index];
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        if (iteration - 1 == i) {
            break;
        }

        if (computed) {
            prev[tx] = curr[tx];
        }

        barrier(CLK_LOCAL_MEM_FENCE);
    }

    if (computed) {
        gpuDst[xidx] = curr[tx];
    }

    (void)rows;
    (void)outputBuffer;
}
